// MessagingHandler is an implementation of the quick.v1.Messaging service.
type MessagingHandler interface {
	ListConversations(context.Context, *connect.Request[v1.ListConversationsRequest]) (*connect.Response[v1.ListConversationsResponse], error)
	OpenDM(context.Context, *connect.Request[v1.OpenDMRequest]) (*connect.Response[v1.OpenDMResponse], error)
	ListMessages(context.Context, *connect.Request[v1.ListMessagesRequest]) (*connect.Response[v1.ListMessagesResponse], error)
	SendMessage(context.Context, *connect.Request[v1.SendMessageRequest]) (*connect.Response[v1.SendMessageResponse], error)
	MarkRead(context.Context, *connect.Request[v1.MarkReadRequest]) (*connect.Response[v1.MarkReadResponse], error)
	CreateGroup(context.Context, *connect.Request[v1.CreateGroupRequest]) (*connect.Response[v1.CreateGroupResponse], error)
	CreateChannel(context.Context, *connect.Request[v1.CreateChannelRequest]) (*connect.Response[v1.CreateChannelResponse], error)
	AddMembers(context.Context, *connect.Request[v1.AddMembersRequest]) (*connect.Response[v1.AddMembersResponse], error)
	RemoveMember(context.Context, *connect.Request[v1.RemoveMemberRequest]) (*connect.Response[v1.RemoveMemberResponse], error)
	LeaveConversation(context.Context, *connect.Request[v1.LeaveConversationRequest]) (*connect.Response[v1.LeaveConversationResponse], error)
	ListMembers(context.Context, *connect.Request[v1.ListMembersRequest]) (*connect.Response[v1.ListMembersResponse], error)
	// S10 — TG parity additions.
	DeleteConversation(context.Context, *connect.Request[v1.DeleteConversationRequest]) (*connect.Response[v1.DeleteConversationResponse], error)
	EditMessage(context.Context, *connect.Request[v1.EditMessageRequest]) (*connect.Response[v1.EditMessageResponse], error)
	DeleteMessage(context.Context, *connect.Request[v1.DeleteMessageRequest]) (*connect.Response[v1.DeleteMessageResponse], error)
	PinMessage(context.Context, *connect.Request[v1.PinMessageRequest]) (*connect.Response[v1.PinMessageResponse], error)
	UnpinMessage(context.Context, *connect.Request[v1.UnpinMessageRequest]) (*connect.Response[v1.UnpinMessageResponse], error)
	GetMessageReaders(context.Context, *connect.Request[v1.GetMessageReadersRequest]) (*connect.Response[v1.GetMessageReadersResponse], error)
	PinConversation(context.Context, *connect.Request[v1.PinConversationRequest]) (*connect.Response[v1.PinConversationResponse], error)
	UnpinConversation(context.Context, *connect.Request[v1.UnpinConversationRequest]) (*connect.Response[v1.UnpinConversationResponse], error)
	// S11 — voice messages. Upload itself is a multipart HTTP POST to /v1/media/voice
	// (not RPC — Connect-RPC is awkward for binary streams). That endpoint returns
	// {file_id, url, duration_ms, peaks}. Then the client calls SendVoiceMessage
	// which writes a kind='voice' message into the thread referencing the file_id.
	SendVoiceMessage(context.Context, *connect.Request[v1.SendVoiceMessageRequest]) (*connect.Response[v1.SendVoiceMessageResponse], error)
	MarkVoicePlayed(context.Context, *connect.Request[v1.MarkVoicePlayedRequest]) (*connect.Response[v1.MarkVoicePlayedResponse], error)
	// S13 — replies, reactions, forwards, attachments, full-text search.
	AddReaction(context.Context, *connect.Request[v1.AddReactionRequest]) (*connect.Response[v1.AddReactionResponse], error)
	RemoveReaction(context.Context, *connect.Request[v1.RemoveReactionRequest]) (*connect.Response[v1.RemoveReactionResponse], error)
	ListReactions(context.Context, *connect.Request[v1.ListReactionsRequest]) (*connect.Response[v1.ListReactionsResponse], error)
	ForwardMessage(context.Context, *connect.Request[v1.ForwardMessageRequest]) (*connect.Response[v1.ForwardMessageResponse], error)
	SearchMessages(context.Context, *connect.Request[v1.SearchMessagesRequest]) (*connect.Response[v1.SearchMessagesResponse], error)
	// E2E group keys. Sender uploads the per-member wrapped key bundle when
	// creating a group or when membership changes; recipients fetch it and
	// decrypt their slot to recover the symmetric conversation key. DMs do
	// NOT use bundles — both peers derive the shared key via ECDH on the fly.
	PutGroupKeyBundle(context.Context, *connect.Request[v1.PutGroupKeyBundleRequest]) (*connect.Response[v1.PutGroupKeyBundleResponse], error)
	GetGroupKeyBundle(context.Context, *connect.Request[v1.GetGroupKeyBundleRequest]) (*connect.Response[v1.GetGroupKeyBundleResponse], error)
}

